/* MAKE SURE ALL INPUT IS VALID INPUT */
function scrubber($incVar, $type){

	switch ($type) {
    	case 'string':
			$incVar = filter_var($incVar, FILTER_SANITIZE_FULL_SPECIAL_CHARS);
			break;
    	case 'string_2024':
			$incVar = strip_tags($incVar);
			break;
    	case 'float':
			$incVar = filter_var($incVar, FILTER_SANITIZE_NUMBER_FLOAT);
			break;
    	case 'int':
			$incVar = filter_var($incVar, FILTER_SANITIZE_NUMBER_INT);
			break;
    	case 'email':
			$incVar = filter_var($incVar, FILTER_SANITIZE_EMAIL);
			break;
    	case 'url':
			$incVar = filter_var($incVar, FILTER_SANITIZE_URL);
			break;
    	case 'array':
			$incVar = implode(',',$incVar);
			$incVar = filter_var($incVar, FILTER_SANITIZE_FULL_SPECIAL_CHARS);
			break;
    	case 'none':
    		// unsafe!
			$incVar = filter_var($incVar, FILTER_UNSAFE_RAW);
			break;
    	case 'filemaker':
			$incVar = htmlspecialchars_decode($incVar);
			// if first and last characters are 'single quote' assume the user is trying to do an exact match and change them to "doulbe quotes" as filemaker doesn't process 'single quote' search that way
			if( substr($incVar, 0, 1) == "'" && substr($incVar, -1, 1) == "'" ){
				$incVar = '"'.substr($incVar, 1, -1).'"';
			}
			break;
	    default:
			$incVar = filter_var($incVar, FILTER_SANITIZE_FULL_SPECIAL_CHARS);
	}

	if( is_string($incVar) ){
		$incVar = stripslashes($incVar);
	}

	return $incVar;
}


/* SHORTEN URLS BY TYPE */
function getDocType($doc)
{
	if (strpos($doc, '.pdf') !== FALSE) {
		$doc = 'PDF';
	} else if (strpos($doc, '.doc') !== FALSE || strpos($doc, '.docx') !== FALSE) {
		$doc = 'Word Document';
	} else if (strpos($doc, '.xls') !== FALSE || strpos($doc, '.xlsx') !== FALSE) {
		$doc = 'Excel Document';
	} else {
		$doc = 'Link';
	}
	return $doc;
}


date_default_timezone_set('America/New_York');


# fix all the punctation errors in the references...
function getPeriod($badData){
	if (substr($badData, strlen($badData) - 1) != '?' && substr($badData, strlen($badData) - 1) != '.' && $badData != ''){
		return '.';
	}
}


